#!/usr/bin/env python3
"""
Bug #1294: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['normalization', 'manual_rmsnorm_last_axis'], ['attention', 'gated_mlp_block'], ['branch', 'where_mask_fill'], ['branch', 'gated_residual'], ['broadcast', 'cumsum_last_axis'], ['layout', 'transpose_matmul_transpose']]
Dependencies: numpy jax
Run         : python unique_1294.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w5 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("000080bf"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 128])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 128])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 128])
_w10 = np.frombuffer(bytes.fromhex("00000040"), dtype=np.float32).reshape([1])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64, 128])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_mrn_sq = x * x
    n0_mrn_mn = jnp.mean(n0_mrn_sq, axis=(-1,), keepdims=True)
    n0_mrn_ad = n0_mrn_mn + _w0
    n0_mrn_sr = jnp.sqrt(n0_mrn_ad)
    n0_mrn_dv = x / n0_mrn_sr
    n0_mrn_out = n0_mrn_dv * _w1
    n100_gmlp_gate = jnp.matmul(n0_mrn_out, _w2)
    n100_gmlp_up = jnp.matmul(n0_mrn_out, _w3)
    n100_gmlp_sig = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n100_gmlp_gate)))
    n100_gmlp_silu = n100_gmlp_gate * n100_gmlp_sig
    n100_gmlp_mix = n100_gmlp_silu * n100_gmlp_up
    n100_gmlp_out = jnp.matmul(n100_gmlp_mix, _w4)
    n200_wmf_gt = (n100_gmlp_out > _w5)
    n200_wmf_wh = jnp.where(n200_wmf_gt, n100_gmlp_out, _w6)
    n200_wmf_out = n200_wmf_wh * n100_gmlp_out
    n300_gr_sc = n200_wmf_out * _w9
    n300_gr_gate = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-_w7)))
    n300_gr_inv = _w8 - n300_gr_gate
    n300_gr_lhs = n300_gr_sc * n300_gr_gate
    n300_gr_rhs = n200_wmf_out * n300_gr_inv
    n300_gr_out = n300_gr_lhs + n300_gr_rhs
    n400_cs_out = jnp.cumsum(n300_gr_out, axis=int(_w10.flat[0]))
    n500_tmmt_tr1 = jnp.transpose(n400_cs_out, [0, 2, 1])
    n500_tmmt_tr2 = jnp.transpose(n500_tmmt_tr1, [0, 2, 1])
    n500_tmmt_mm = jnp.matmul(n500_tmmt_tr2, _w11)
    n500_tmmt_out = jnp.transpose(n500_tmmt_mm, [0, 2, 1])
    n500_tmmt_final = jnp.transpose(n500_tmmt_out, [0, 2, 1])
    return jnp.asarray(n500_tmmt_final, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
